mapper.select:
SELECT B.BOARD_NO, B.BOARD_TITLE, B.BOARD_STATUS, B.BOARD_VIEW, COUNT(DISTINCT L.MEMBER_NO) AS BOARD_LIKE, COUNT(DISTINCT C.BOARD_COMMENT_NO) AS BOARD_COMMENT, DATE_FORMAT(B.BOARD_DATE, '%Y-%m-%d') AS BOARD_DATE FROM BOARD_TBL B JOIN MEMBER_TBL M ON B.MEMBER_NO = M.MEMBER_NO LEFT JOIN BOARD_LIKE_TBL L ON B.BOARD_NO = L.BOARD_NO LEFT JOIN BOARD_COMMENT_TBL C ON B.BOARD_NO = C.BOARD_NO B.MEMBER_NO = #{memberNo}
GROUP BY B.BOARD_NO
ORDER BY B.BOARD_NO DESC
ORDER BY B.BOARD_DATE DESC
ORDER BY B.BOARD_VIEW DESC
LIMIT #{request.offset}, #{request.size}

mapper.update:
UPDATE BOARD_TBL
SET BOARD_STATUS = 2
WHERE BOARD_NO = #{boardNo}

mapper.select:
SELECT PLACE_NO
FROM BOARD_PLACE_TBL
WHERE PLACE_NAME = #{placeName}
  AND ADDRESS_NAME = #{addressName}

SELECT COUNT(*)
FROM BOARD_LIKE_TBL
WHERE BOARD_NO = #{boardNo}

SELECT COUNT(*)
FROM BOARD_LIKE_TBL
WHERE BOARD_NO = #{boardNo}
  AND MEMBER_NO = #{memberNo}

mapper.insert:
INSERT INTO BOARD_LIKE_TBL
(
    MEMBER_NO,
    BOARD_NO
)
VALUES
    (
        #{memberNo},
        #{boardNo}
    )

mapper.delete:
DELETE FROM BOARD_LIKE_TBL
WHERE MEMBER_NO = #{memberNo}
  AND BOARD_NO = #{boardNo}

mapper.select:
