WHERE BOARD_NO = #{boardNo}

SELECT COUNT(*)
FROM BOARD_REPORT_TBL
WHERE BOARD_NO = #{boardNo}
  AND MEMBER_NO = #{memberNo}

mapper.delete:
DELETE FROM BOARD_REPORT_TBL
