  AND BOARD_NO = #{boardNo}

mapper.select:
SELECT MEMBER_NO
FROM MEMBER_TBL
WHERE MEMBER_ID = #{memberId}

mapper.update:
UPDATE BOARD_COMMENT_TBL
SET BOARD_COMMENT_CONTENT = #{boardCommentContent}
WHERE BOARD_COMMENT_NO = #{boardCommentNo}

UPDATE BOARD_TBL
SET BOARD_STATUS = #{boardStatus}
WHERE BOARD_NO = #{boardNo}

UPDATE BOARD_COMMENT_TBL
SET BOARD_COMMENT_STATUS = #{commentStatus}
WHERE BOARD_COMMENT_NO = #{boardCommentNo}

UPDATE BOARD_COMMENT_TBL
SET BOARD_COMMENT_STATUS = 2
WHERE BOARD_COMMENT_NO = #{boardCommentNo}

mapper.select:
SELECT COUNT(*)
FROM BOARD_COMMENT_REPORT_TBL
WHERE BOARD_COMMENT_NO = #{boardCommentNo}
  AND MEMBER_NO = #{memberNo}

mapper.delete:
DELETE FROM BOARD_COMMENT_REPORT_TBL
WHERE MEMBER_NO = #{memberNo}
  AND BOARD_COMMENT_NO = #{boardCommentNo}
